        all_pkgs = sorted(set(list(bpkgs.keys()) + list(apkgs.keys())))
        for pkg in all_pkgs:
            bv = bpkgs.get(pkg)
            av = apkgs.get(pkg)
            if bv != av:
                changes.append((proj, fw, pkg, bv or 'N/A', av or 'N/A'))
            else:
                unchanged.append((proj, fw, pkg, bv))

print("=== CHANGES ===")
